import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    best_node = None
    min_penalty = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        distance = calculate_distance(cur_truck_pos, customer_pos)
        travel_time = distance / truck_speed
        arrival_time = current_time + travel_time

        start_window, end_window = time_windows[i]
        if arrival_time < start_window:
            time_penalty = (start_window - arrival_time)**2  # square penalty for early arrival
        elif arrival_time > end_window:
            time_penalty = (arrival_time - end_window)**2 * 10  # square penalty for late, scaled up
        else:
            time_penalty = 0  # no penalty if in the time window

        collaborative_penalty = 0
        for other_truck_pos in all_truck_pos:
            if np.array_equal(other_truck_pos, cur_truck_pos):
                continue
            if calculate_distance(other_truck_pos, customer_pos) < calculate_distance(cur_truck_pos, customer_pos):
                collaborative_penalty += calculate_distance(other_truck_pos, customer_pos)

        total_penalty = time_penalty + collaborative_penalty

        if total_penalty < min_penalty:
            min_penalty = total_penalty
            best_node = i

    return best_node

