        return arrival_time - current_time + waiting_cost + 0.3 * proximity_cost + depot_penalty

    efficiency_scores = [calculate_efficiency_score(customer, time_windows[i]) for i, customer in enumerate(unvisited_customers)]
    best_node = min(range(len(efficiency_scores)), key=lambda i: efficiency_scores[i])

