def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    def estimated_time_of_arrival(position, destination):
        return current_time + distance(position, destination) / truck_speed

    def potential_gain(position):
        # We calculate how closely other unvisited customers are located to the given position, incentivizing clustering
        threshold = np.median([distance(position, other) for other in unvisited_customers if not np.array_equal(position, other)])
        close_customers = [1 for other in unvisited_customers if distance(position, other) < threshold]
        gain = sum(close_customers)
        return gain

    best_node = None
    min_expected_cost = float('inf')

    for i, customer in enumerate(unvisited_customers):
        arrival_time = estimated_time_of_arrival(cur_truck_pos, customer)
        window_start, window_end = time_windows[i]

        # Calculate immediate cost
        if arrival_time < window_start:
            immediate_cost = (window_start - arrival_time)  # waiting cost
        elif arrival_time > window_end:
            immediate_cost = (arrival_time - window_end) * 10  # late penalty
        else:
            immediate_cost = 0

        # Calculate potential future benefits (gain) from choosing this customer
        gain = potential_gain(customer)

        # In total cost, a positive gain will decrease the cost
        total_cost = immediate_cost - gain

        if total_cost < min_expected_cost:
            min_expected_cost = total_cost
            best_node = i

    return best_node

