def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(pos1, pos2):
        return np.linalg.norm(pos1 - pos2) / truck_speed

    def evaluate_time_window_cost(arrival_time, window):
        start, end = window
        if arrival_time < start:
            return np.exp(start - arrival_time)  # Exponential penalty for early arrival
        elif arrival_time > end:
            return np.exp(arrival_time - end)  # Exponential penalty for late arrival
        else:
            return 0  # No penalty   

    best_node = None
    min_cost = float('inf')

    for i, customer in enumerate(unvisited_customers):
        time_to_customer = travel_time(cur_truck_pos, customer)
        time_to_depot = travel_time(customer, depot_pos)
        time_return_to_depot = travel_time(cur_truck_pos, depot_pos)

        arrival_time = current_time + time_to_customer
        time_window_cost = evaluate_time_window_cost(arrival_time, time_windows[i])

        # Combined cost considering time to customer, time window cost, and eventual return to depot
        total_cost = time_window_cost + time_to_customer + 0.5 * time_to_depot + 0.3 * time_return_to_depot

        if total_cost < min_cost:
            min_cost = total_cost
            best_node = i

    return best_node
